import { useEffect, useRef } from 'react';

export function EchoText({ children, tag: Tag = 'span', color = 'var(--color-accent)' }) {
  const ref = useRef(null);
  const echoRef = useRef(null);

  useEffect(() => {
    let raf, targetX = 0, targetY = 0, cx = 0, cy = 0;
    const track = (e) => {
      const rect = ref.current.getBoundingClientRect();
      targetX = (e.clientX - rect.left - rect.width / 2) * 0.12;
      targetY = (e.clientY - rect.top - rect.height / 2) * 0.08;
    };
    const loop = () => {
      cx += (targetX - cx) * 0.06;
      cy += (targetY - cy) * 0.06;
      if (echoRef.current) {
        echoRef.current.style.transform = `translate(${cx + 3}px, ${cy + 2}px)`;
      }
      raf = requestAnimationFrame(loop);
    };
    const el = ref.current;
    el.addEventListener('mousemove', track);
    el.addEventListener('mouseleave', () => { targetX = 0; targetY = 0; });
    raf = requestAnimationFrame(loop);
    return () => {
      el.removeEventListener('mousemove', track);
      cancelAnimationFrame(raf);
    };
  }, []);

  return (
    <Tag ref={ref} style={{ position: 'relative', display: 'inline-block' }}>
      <span style={{ position: 'relative', zIndex: 1 }}>{children}</span>
      <span ref={echoRef} aria-hidden="true" style={{
        position: 'absolute', inset: 0,
        opacity: 0.3, color: color,
        pointerEvents: 'none', zIndex: 0,
        transition: 'transform 0.1s ease-out'
      }}>{children}</span>
    </Tag>
  );
}

velocity_cursor.code:
export class VelocityCursor {
  constructor(el) {
    this.el = el;
    this.x = -100; this.y = -100;
    this.tx = -100; this.ty = -100;
    this.lx = -100; this.ly = -100;
    document.addEventListener('mousemove', (e) => {
      this.tx = e.clientX; this.ty = e.clientY;
    });
    if ('ontouchstart' in window) { el.style.display = 'none'; return; }
    this.loop();
  }
  loop() {
    const vx = this.tx - this.lx;
    const vy = this.ty - this.ly;
    this.lx = this.x; this.ly = this.y;
    this.x += (this.tx - this.x) * 0.1;
    this.y += (this.ty - this.y) * 0.1;
    const speed = Math.sqrt(vx * vx + vy * vy);
    const stretch = Math.min(1 + speed * 0.04, 2.2);
    const angle = Math.atan2(vy, vx) * (180 / Math.PI);
    this.el.style.transform = `translate(${this.x}px, ${this.y}px) rotate(${angle}deg) scaleX(${stretch}) scaleY(${1 / stretch})`;
    requestAnimationFrame(this.loop.bind(this));
  }
}

magnetic_element.code:
import gsap from 'gsap';

export function initMagnetic(el, strength = 0.3) {
  const xTo = gsap.quickTo(el, 'x', { duration: 0.8, ease: 'power3.out' });
  const yTo = gsap.quickTo(el, 'y', { duration: 0.8, ease: 'power3.out' });

  el.addEventListener('mousemove', (e) => {
    const { clientX, clientY } = e;
    const { left, top, width, height } = el.getBoundingClientRect();
    const x = (clientX - (left + width / 2)) * strength;
    const y = (clientY - (top + height / 2)) * strength;
    xTo(x);
    yTo(y);
  });

  el.addEventListener('mouseleave', () => {
    xTo(0);
    yTo(0);
  });
}

word_reveal.code:
import gsap from 'gsap';

export function splitAndReveal(el, trigger = 'viewport') {
  const words = el.innerText.split(' ');
  el.innerHTML = words.map(w => `<span class="word-wrap" style="overflow:hidden; display:inline-block;"><span class="word-inner" style="display:inline-block;">${w}</span></span>`).join(' ');
  const inners = el.querySelectorAll('.word-inner');
  gsap.fromTo(inners, { yPercent: 100 }, {
    yPercent: 0, duration: 0.8, stagger: 0.04, ease: 'power4.out',
    scrollTrigger: trigger === 'viewport' ? {
      trigger: el, start: 'top 85%', toggleActions: 'play none none none'
    } : null
  });
}

