export function startGlitchCount(el, targetValue, duration = 2000) {
  const chars = '0123456789X$/%';
  const start = performance.now();
  const loop = (now) => {
    const elapsed = now - start;
    const progress = Math.min(elapsed / duration, 1);
    if (progress < 1) {
      const text = Math.floor(targetValue * progress).toString();
      const glitched = text.split('').map(c => Math.random() > 0.6 ? chars[Math.floor(Math.random() * chars.length)] : c).join('');
      el.innerText = glitched;
      requestAnimationFrame(loop);
    } else {
      el.innerText = targetValue.toString();
    }
  };
  requestAnimationFrame(loop);
}

horizontal_scroll.code:
import gsap from 'gsap';

export function setupHorizontalScroll(pinSection, container) {
  const scrollWidth = container.offsetWidth - window.innerWidth;
  gsap.to(container, {
    x: -scrollWidth, ease: 'none',
    scrollTrigger: {
      trigger: pinSection, pin: true, scrub: true,
      start: 'top top', end: () => `+=${scrollWidth}`
    }
  });
}

