page_transition.code:
import gsap from 'gsap';

export function wipeTransition(overlayElement, onComplete) {
  const tl = gsap.timeline({ onComplete });
  tl.fromTo(overlayElement, { clipPath: 'inset(100% 0 0 0)' }, {
    clipPath: 'inset(0 0 0 0)', duration: 0.6, ease: 'power4.in'
  }).to(overlayElement, {
    clipPath: 'inset(0 0 100% 0)', duration: 0.6, ease: 'power4.out', delay: 0.25
  });
}

