import RAPIER from '@dimforge/rapier2d';

export class PhysicsStickers {
  constructor(canvas) {
    this.world = new RAPIER.World({ x: 0.0, y: -9.81 });
    this.canvas = canvas;
    this.bodies = [];
    this.initBoundaries();
  }
  initBoundaries() {
    const w = this.canvas.width / 100;
    const h = this.canvas.height / 100;
    const ground = RAPIER.RigidBodyDesc.fixed();
    this.world.createCollider(RAPIER.ColliderDesc.cuboid(w, 0.1), this.world.createRigidBody(ground));
  }
  step() {
    this.world.step();
  }
}

