import * as THREE from 'three';

const vertexShader = `varying vec2 vUv; void main() { vUv = uv; gl_Position = vec4(position, 1.0); }`;
const fragmentShader = `varying vec2 vUv; uniform float uTime; float noise(vec2 p) { return fract(sin(dot(p, vec2(127.1, 311.7))) * 43758.5453); } void main() { vec2 uv = vUv; float n = noise(uv * 100.0 + sin(uTime)); gl_FragColor = vec4(vec3(n * 0.05), 1.0); }`;

export function createNoisePlane() {
  const material = new THREE.ShaderMaterial({ vertexShader, fragmentShader, uniforms: { uTime: { value: 0.0 } } });
  const mesh = new THREE.Mesh(new THREE.PlaneGeometry(2, 2), material);
  return { mesh, material };
}

