import gsap from 'gsap';

export function setupVideoScrub(video, triggerSection) {
  video.pause();
  video.currentTime = 0;
  gsap.to(video, {
    currentTime: video.duration || 5, ease: 'none',
    scrollTrigger: {
      trigger: triggerSection, scrub: true, start: 'top top', end: 'bottom bottom'
    }
  });
}

