import gsap from 'gsap';

export function initMarquee(trackElement, speed = 100) {
  const width = trackElement.scrollWidth;
  gsap.to(trackElement, {
    x: -width / 2, ease: 'none', repeat: -1,
    duration: width / speed
  });
}

