import gsap from 'gsap';

export function startLoader(counterEl, awardsEl, onComplete) {
  let progress = { value: 0 };
  gsap.to(progress, {
    value: 100, duration: 2.2, ease: 'power2.inOut',
    onUpdate: () => { counterEl.innerText = `${Math.floor(progress.value)}%`; },
    onComplete: () => {
      gsap.to([counterEl, awardsEl], { opacity: 0, duration: 0.4, onComplete });
    }
  });
}

post_processing.code:
import { EffectComposer, RenderPass, EffectPass, BloomEffect } from 'postprocessing';

export function setupEffects(renderer, scene, camera) {
  const composer = new EffectComposer(renderer);
  composer.addPass(new RenderPass(scene, camera));
  const bloom = new BloomEffect({ intensity: 0.5 });
  composer.addPass(new EffectPass(camera, bloom));
  return composer;
}

