import { Howl } from 'howler';

export class SoundManager {
  constructor() {
    this.sounds = {};
  }
  load(id, src) {
    this.sounds[id] = new Howl({ src: [src], volume: 0.5 });
  }
  play(id) {
    if (this.sounds[id]) this.sounds[id].play();
  }
  setVolume(id, vol) {
    if (this.sounds[id]) this.sounds[id].volume(vol);
  }
}
